                    <input class="form-check-input" type="checkbox" id="weeklyDigest"
                           checked="@_editNotifications.WeeklyDigest"
                           @onchange="e => _editNotifications.WeeklyDigest = (bool)e.Value!" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>

            <h6>Muted Channels</h6>
            <p class="text-muted small">Uncheck channels you'd like to mute.</p>
            <div class="channel-list mb-4">
                @for (var i = 0; i < _allChannels.Count; i++)
                {
                    var channel = _allChannels[i];
                    var isMuted = _editNotifications.MutedChannels.Contains(channel);
                    var idx = i;
                    <div class="form-check mb-2">
                        <input class="form-check-input darker-border-checkbox" type="checkbox"
                               id="ch-@idx"
                               checked="@(!isMuted)"
                               @onchange="e => ToggleChannel(channel, !(bool)e.Value!)" />
                        <label class="form-check-label" for="ch-@idx">#@channel</label>
                    </div>
                }
            </div>

            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </section>;
}

@* ───────────── Security Section ───────────── *@

@{
    RenderFragment RenderSecurity() =>
        @<section class="settings-section">
            <h4>Security</h4>
            <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>
            <hr />

            @* Change Password *@
            <div class="card mb-4">
                <div class="card-header d-flex align-items-center justify-content-between"
                     role="button" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                        @if (_security?.LastPasswordChange is not null)
                        {
                            <p class="text-muted small mt-2 mb-0">
                                Last changed: @_security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                            </p>
                        }
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="card mb-4">
                <div class="card-body d-flex align-items-center justify-content-between">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
                    </div>
                </div>
            </div>

            @* Active Sessions *@
            <h6>Active Sessions</h6>
            @if (_security?.Sessions.Count > 0)
            {
                <div class="table-responsive">
                    <table class="table table-hover align-middle">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session.Id == _security.Sessions[0].Id;
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td class="text-end">
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions.</p>
            }

            @* Revoke Confirmation Dialog *@
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop show"></div>
                <div class="modal d-block" tabindex="-1">
                    <div class="modal-dialog modal-dialog-centered">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </section>;
}

@* ───────────── Appearance Section ───────────── *@

@{
    RenderFragment RenderAppearance() =>
        @<section class="settings-section">
            <h4>Appearance</h4>
            <p class="text-muted">Customize how the application looks.</p>
            <hr />

            <div class="row g-4">
                <div class="col-md-6">
                    @* Theme *@
                    <div class="mb-4">
                        <h6>Theme</h6>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="theme-@theme" value="@theme"
                                       checked="@(_editAppearance!.Theme == theme)"
                                       @onchange="() => _editAppearance!.Theme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>

                    @* Font Size *@
                    <div class="mb-4">
                        <h6>Font Size</h6>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="fs-@size" value="@size"
                                       checked="@(_editAppearance!.FontSize == size)"
                                       @onchange="() => _editAppearance!.FontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>

                    @* Language *@
                    <div class="mb-4">
                        <h6>Language</h6>
                        <select class="form-select" @bind="_editAppearance!.Language">
                            <option value="English">English</option>
                            <option value="Spanish">Spanish</option>
                            <option value="French">French</option>
                            <option value="German">German</option>
                            <option value="Japanese">Japanese</option>
                            <option value="Chinese">Chinese</option>
                        </select>
                    </div>

                    @* Compact Mode *@
                    <div class="mb-4">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode"
                                   checked="@_editAppearance!.CompactMode"
                                   @onchange="e => _editAppearance!.CompactMode = (bool)e.Value!" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>

                @* Live Preview *@
                <div class="col-md-6">
                    <h6>Preview</h6>
                    <div class="live-preview @GetPreviewClasses()">
                        <div class="preview-header">Application Header</div>
                        <div class="preview-body">
                            <p class="preview-text">This is a preview of your selected appearance settings.</p>
                            <div class="preview-card">
                                <strong>Sample Card</strong>
                                <p class="mb-0">Content adapts to your chosen theme, font size, and density.</p>
                            </div>
                            <button class="preview-btn">Sample Button</button>
                        </div>
                        <div class="preview-footer">
                            Theme: @_editAppearance!.Theme · Font: @_editAppearance.FontSize · @_editAppearance.Language
                            @if (_editAppearance.CompactMode) { <span> · Compact</span> }
                        </div>
                    </div>
                </div>
            </div>
        </section>;
}

@code {
    private record SectionInfo(string Label, string Icon);

    private readonly Dictionary<string, SectionInfo> _sections = new()
    {
        ["profile"] = new("Profile", "👤"),
        ["notifications"] = new("Notifications", "🔔"),
        ["security"] = new("Security", "🔒"),
        ["appearance"] = new("Appearance", "🎨"),
    };

    private string ActiveSection { get; set; } = "profile";

    // Data
    private UserProfile? _savedProfile;
    private NotificationPrefs? _savedNotifications;
    private SecuritySettings? _security;
    private AppearanceSettings? _savedAppearance;

    // Editable copies (mutable helper classes)
    private ProfileEdit? _editProfile;
    private NotificationEdit? _editNotifications;
    private AppearanceEdit? _editAppearance;

    // Security helpers
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private ActiveSession? _sessionToRevoke;

    // All available channels (superset)
    private readonly List<string> _allChannels = new()
        { "general", "random", "announcements", "dev-ops", "design" };

    // UI state
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appTask);

        _savedProfile = profileTask.Result;
        _savedNotifications = notifTask.Result;
        _security = secTask.Result;
        _savedAppearance = appTask.Result;

        _editProfile = ProfileEdit.From(_savedProfile);
        _editNotifications = NotificationEdit.From(_savedNotifications);
        _twoFactorEnabled = _security.TwoFactorEnabled;
        _editAppearance = AppearanceEdit.From(_savedAppearance);

        _loading = false;
    }

    // ─── Profile ────────────────────────────────────────
    private async Task SaveProfile()
    {
        _saving = true;
        var profile = _editProfile!.ToRecord();
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfile()
    {
        _editProfile = ProfileEdit.From(_savedProfile!);
        ShowToast("Changes discarded.");
    }

    // ─── Notifications ─────────────────────────────────
    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !_editNotifications!.MutedChannels.Contains(channel))
            _editNotifications.MutedChannels.Add(channel);
        else if (!muted)
            _editNotifications!.MutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = _editNotifications!.ToRecord();
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _savedNotifications = prefs;
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ─── Security ───────────────────────────────────────
    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", isError: true);
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = _newPassword = _confirmPassword = "";
        _passwordPanelOpen = false;
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ─── Appearance ─────────────────────────────────────
    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = _editAppearance!.ToRecord();
        await SettingsService.SaveAppearanceAsync(settings);
        _savedAppearance = settings;
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_editAppearance!.Theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(_editAppearance.FontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_editAppearance.CompactMode)
            classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    // ─── Helpers ────────────────────────────────────────
    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _ = DismissToastAfterDelay();
    }

    private async Task DismissToastAfterDelay()
    {
        await Task.Delay(4000);
        _toastMessage = null;
        await InvokeAsync(StateHasChanged);
    }

    private void DismissToast() => _toastMessage = null;

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ─── Mutable edit models (records are immutable) ────
    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";

        public static ProfileEdit From(UserProfile p) => new()
        {
            DisplayName = p.DisplayName,
            Email = p.Email,
            AvatarUrl = p.AvatarUrl,
            Bio = p.Bio
        };

        public UserProfile ToRecord() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private class NotificationEdit
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = new();

        public static NotificationEdit From(NotificationPrefs p) => new()
        {
            EmailNotifications = p.EmailNotifications,
            PushNotifications = p.PushNotifications,
            WeeklyDigest = p.WeeklyDigest,
            MutedChannels = new List<string>(p.MutedChannels)
        };

        public NotificationPrefs ToRecord() =>
            new(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }

        public static AppearanceEdit From(AppearanceSettings a) => new()
        {
            Theme = a.Theme,
            FontSize = a.FontSize,
            Language = a.Language,
            CompactMode = a.CompactMode
        };

        public AppearanceSettings ToRecord() => new(Theme, FontSize, Language, CompactMode);
    }
}

/* ── Layout ──────────────────────────────────────── */

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
