{"file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_0ece779dc6e546c2b040ab63b035e986.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => ActiveSection = section.Key">
                        <span class="section-icon">@section.Value.Icon</span>
                        @section.Value.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else
        {
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="toast-banner @(_toastIsError ? "toast-error" : "toast-success")">
                    @_toastMessage
                    <button class="btn-close btn-close-sm ms-2" @onclick="DismissToast"></button>
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }
    </div>
</div>

@* ───────────── Profile Section ───────────── *@

@{
    RenderFragment RenderProfile() =>
        @<section class="settings-section">
            <h4>Profile</h4>
            <p class="text-muted">Manage your personal information.</p>
            <hr />

            <div class="row g-4">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label class="form-label">Display Name</label>
                        <input class="form-control" @bind="_editProfile!.DisplayName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Email</label>
                        <input type="email" class="form-control" @bind="_editProfile.Email" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Bio</label>
                        <textarea class="form-control" rows="4" @bind="_editProfile.Bio"></textarea>
                    </div>
                </div>
                <div class="col-md-4">
                    <label class="form-label">Avatar Preview</label>
                    <div class="avatar-preview">
                        @if (!string.IsNullOrWhiteSpace(_editProfile.AvatarUrl))
                        {
                            <img src="@_editProfile.AvatarUrl" alt="Avatar" class="avatar-img" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">No avatar</div>
                        }
                    </div>
                    <div class="mt-2">
                        <label class="form-label">Avatar URL</label>
                        <input class="form-control form-control-sm" @bind="_editProfile.AvatarUrl" />
                    </div>
                </div>
            </div>

            <div class="mt-4 d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
