@* ───────────── Notifications Section ───────────── *@

@{
    RenderFragment RenderNotifications() =>
        @<section class="settings-section">
            <h4>Notifications</h4>
            <p class="text-muted">Choose how you want to be notified.</p>
            <hr />

            <div class="mb-4">
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif"
                           checked="@_editNotifications!.EmailNotifications"
                           @onchange="e => _editNotifications.EmailNotifications = (bool)e.Value!" />
                    <label class="form-check-label" for="emailNotif">Email Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif"
                           checked="@_editNotifications.PushNotifications"
                           @onchange="e => _editNotifications.PushNotifications = (bool)e.Value!" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest"
                           checked="@_editNotifications.WeeklyDigest"
                           @onchange="e => _editNotifications.WeeklyDigest = (bool)e.Value!" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>

            <h6>Muted Channels</h6>
            <p class="text-muted small">Uncheck channels you'd like to mute.</p>
            <div class="channel-list mb-4">
                @for (var i = 0; i < _allChannels.Count; i++)
                {
                    var channel = _allChannels[i];
                    var isMuted = _editNotifications.MutedChannels.Contains(channel);
                    var idx = i;
                    <div class="form-check mb-2">
                        <input class="form-check-input darker-border-checkbox" type="checkbox"
                               id="ch-@idx"
                               checked="@(!isMuted)"
                               @onchange="e => ToggleChannel(channel, !(bool)e.Value!)" />
                        <label class="form-check-label" for="ch-@idx">#@channel</label>
                    </div>
                }
            </div>

            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </section>;
}

@* ───────────── Security Section ───────────── *@

@{
    RenderFragment RenderSecurity() =>
        @<section class="settings-section">
            <h4>Security</h4>
            <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>
            <hr />

            @* Change Password *@
            <div class="card mb-4">
                <div class="card-header d-flex align-items-center justify-content-between"
                     role="button" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                        @if (_security?.LastPasswordChange is not null)
                        {
                            <p class="text-muted small mt-2 mb-0">
                                Last changed: @_security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                            </p>
                        }
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="card mb-4">
                <div class="card-body d-flex align-items-center justify-content-between">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
                    </div>
                </div>
            </div>

            @* Active Sessions *@
            <h6>Active Sessions</h6>
            @if (_security?.Sessions.Count > 0)
            {
                <div class="table-responsive">
                    <table class="table table-hover align-middle">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session.Id == _security.Sessions[0].Id;
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td class="text-end">
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions.</p>
            }

            @* Revoke Confirmation Dialog *@
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop show"></div>
                <div class="modal d-block" tabindex="-1">
                    <div class="modal-dialog modal-dialog-centered">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </section>;
}

@* ───────────── Appearance Section ───────────── *@

@{
    RenderFragment RenderAppearance() =>
        @<section class="settings-section">
            <h4>Appearance</h4>
            <p class="text-muted">Customize how the application looks.</p>
            <hr />

            <div class="row g-4">
                <div class="col-md-6">
