                    </div>
                </div>
            </div>
        </section>;
}

@code {
    private record SectionInfo(string Label, string Icon);

    private readonly Dictionary<string, SectionInfo> _sections = new()
    {
        ["profile"] = new("Profile", "👤"),
        ["notifications"] = new("Notifications", "🔔"),
        ["security"] = new("Security", "🔒"),
        ["appearance"] = new("Appearance", "🎨"),
    };

    private string ActiveSection { get; set; } = "profile";

    // Data
    private UserProfile? _savedProfile;
    private NotificationPrefs? _savedNotifications;
    private SecuritySettings? _security;
    private AppearanceSettings? _savedAppearance;

    // Editable copies (mutable helper classes)
    private ProfileEdit? _editProfile;
    private NotificationEdit? _editNotifications;
    private AppearanceEdit? _editAppearance;

    // Security helpers
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private ActiveSession? _sessionToRevoke;

    // All available channels (superset)
    private readonly List<string> _allChannels = new()
        { "general", "random", "announcements", "dev-ops", "design" };

    // UI state
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appTask);

        _savedProfile = profileTask.Result;
        _savedNotifications = notifTask.Result;
        _security = secTask.Result;
        _savedAppearance = appTask.Result;

        _editProfile = ProfileEdit.From(_savedProfile);
        _editNotifications = NotificationEdit.From(_savedNotifications);
        _twoFactorEnabled = _security.TwoFactorEnabled;
        _editAppearance = AppearanceEdit.From(_savedAppearance);

        _loading = false;
    }

    // ─── Profile ────────────────────────────────────────
    private async Task SaveProfile()
    {
        _saving = true;
        var profile = _editProfile!.ToRecord();
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfile()
    {
        _editProfile = ProfileEdit.From(_savedProfile!);
        ShowToast("Changes discarded.");
    }

    // ─── Notifications ─────────────────────────────────
    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !_editNotifications!.MutedChannels.Contains(channel))
            _editNotifications.MutedChannels.Add(channel);
        else if (!muted)
            _editNotifications!.MutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = _editNotifications!.ToRecord();
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _savedNotifications = prefs;
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ─── Security ───────────────────────────────────────
    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", isError: true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", isError: true);
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = _newPassword = _confirmPassword = "";
        _passwordPanelOpen = false;
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ─── Appearance ─────────────────────────────────────
    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = _editAppearance!.ToRecord();
        await SettingsService.SaveAppearanceAsync(settings);
        _savedAppearance = settings;
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_editAppearance!.Theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(_editAppearance.FontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_editAppearance.CompactMode)
            classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    // ─── Helpers ────────────────────────────────────────
    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _ = DismissToastAfterDelay();
    }

    private async Task DismissToastAfterDelay()
    {
        await Task.Delay(4000);
        _toastMessage = null;
        await InvokeAsync(StateHasChanged);
    }

    private void DismissToast() => _toastMessage = null;

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ─── Mutable edit models (records are immutable) ────
    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";

        public static ProfileEdit From(UserProfile p) => new()
        {
            DisplayName = p.DisplayName,
            Email = p.Email,
            AvatarUrl = p.AvatarUrl,
            Bio = p.Bio
        };

        public UserProfile ToRecord() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private class NotificationEdit
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = new();

        public static NotificationEdit From(NotificationPrefs p) => new()
        {
            EmailNotifications = p.EmailNotifications,
            PushNotifications = p.PushNotifications,
            WeeklyDigest = p.WeeklyDigest,
            MutedChannels = new List<string>(p.MutedChannels)
        };

        public NotificationPrefs ToRecord() =>
            new(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }

        public static AppearanceEdit From(AppearanceSettings a) => new()
        {
            Theme = a.Theme,
            FontSize = a.FontSize,
            Language = a.Language,
            CompactMode = a.CompactMode
        };

        public AppearanceSettings ToRecord() => new(Theme, FontSize, Language, CompactMode);
    }
}
